import React, { useState } from 'react';
import { Deal, InvestmentAccountType } from '../types';
import { MOCK_ACCOUNTS } from '../constants';
import { Card, Button, Badge } from './UIElements';
import { X, CheckCircle2, ChevronRight, Landmark } from 'lucide-react';

interface InvestmentModalProps {
  deal: Deal;
  onClose: () => void;
  onSubmit: (data: any) => void;
}

export const InvestmentModal: React.FC<InvestmentModalProps> = ({ deal, onClose, onSubmit }) => {
  const [step, setStep] = useState(1);
  const [amount, setAmount] = useState(deal.minimum_investment);
  const [account, setAccount] = useState(MOCK_ACCOUNTS[0].id);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleNext = () => setStep(s => s + 1);
  const handleBack = () => setStep(s => s - 1);

  const handleSubmit = async () => {
    setIsSubmitting(true);
    // Simulate API call
    await new Promise(r => setTimeout(r, 1500));
    onSubmit({ dealId: deal.id, amount, accountId: account });
    setStep(4);
    setIsSubmitting(false);
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-[#081C3A]/90 backdrop-blur-sm" onClick={onClose}></div>

      <Card className="relative w-full max-w-xl p-0 overflow-hidden animate-in fade-in zoom-in-95 duration-200">
        <div className="p-6 border-b border-white/5 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded bg-[#2F80ED]/10 flex items-center justify-center text-[#2F80ED]">
              <Landmark size={20} />
            </div>
            <div>
              <h2 className="text-lg font-bold text-white tracking-tight uppercase">Capital Allocation</h2>
              <p className="text-xs text-[#8FAEDB]">{deal.title}</p>
            </div>
          </div>
          <button onClick={onClose} className="text-[#8FAEDB] hover:text-white transition-colors">
            <X size={20} />
          </button>
        </div>

        <div className="p-8">
          {step === 1 && (
            <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
              <div className="space-y-4">
                <label className="text-xs font-bold text-[#8FAEDB] uppercase tracking-widest">Select Investment Account</label>
                <div className="grid grid-cols-1 gap-3">
                  {MOCK_ACCOUNTS.map(acc => (
                    <button
                      key={acc.id}
                      onClick={() => setAccount(acc.id)}
                      className={`p-4 rounded-lg border text-left transition-all ${
                        account === acc.id 
                          ? 'border-[#2F80ED] bg-[#2F80ED]/5 text-white' 
                          : 'border-white/5 bg-white/5 text-[#8FAEDB] hover:border-white/20'
                      }`}
                    >
                      <div className="flex justify-between items-center">
                        <span className="font-semibold">{acc.display_name}</span>
                        <Badge variant="info">{acc.type}</Badge>
                      </div>
                    </button>
                  ))}
                </div>
              </div>
              <Button onClick={handleNext} className="w-full py-4">Next Step <ChevronRight size={16} className="inline ml-1"/></Button>
            </div>
          )}

          {step === 2 && (
            <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
              <div className="space-y-4">
                <label className="text-xs font-bold text-[#8FAEDB] uppercase tracking-widest">Allocation Amount</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-[#2F80ED] font-bold text-xl">$</span>
                  <input
                    type="number"
                    value={amount}
                    onChange={(e) => setAmount(Number(e.target.value))}
                    className="w-full bg-white/5 border border-white/10 rounded-lg py-4 pl-10 pr-4 text-2xl font-bold text-white outline-none focus:border-[#2F80ED] transition-all"
                  />
                </div>
                <div className="flex justify-between text-[10px] text-[#8FAEDB] uppercase tracking-widest font-bold">
                  <span>Minimum: ${deal.minimum_investment.toLocaleString()}</span>
                  <span>Balance: Unlimited</span>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <Button variant="outline" onClick={handleBack}>Back</Button>
                <Button onClick={handleNext} disabled={amount < deal.minimum_investment}>Confirm Terms</Button>
              </div>
            </div>
          )}

          {step === 3 && (
            <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
              <div className="p-4 rounded-lg bg-yellow-500/10 border border-yellow-500/20 text-xs text-yellow-200/80 leading-relaxed">
                <p className="font-bold mb-2 uppercase">Risk Disclosure</p>
                By clicking "Submit Allocation", you acknowledge that real estate private equity involves risk of capital loss. You attest that you are an Accredited Investor as defined by Rule 501 of Regulation D.
              </div>
              <div className="grid grid-cols-2 gap-4">
                <Button variant="outline" onClick={handleBack} disabled={isSubmitting}>Back</Button>
                <Button onClick={handleSubmit} disabled={isSubmitting}>
                  {isSubmitting ? 'Processing...' : 'Submit Allocation'}
                </Button>
              </div>
            </div>
          )}

          {step === 4 && (
            <div className="py-8 text-center space-y-4 animate-in fade-in zoom-in-95">
              <div className="flex justify-center">
                <div className="w-20 h-20 rounded-full bg-[#00E0C6]/10 flex items-center justify-center text-[#00E0C6] cyan-glow">
                  <CheckCircle2 size={40} />
                </div>
              </div>
              <h2 className="text-2xl font-bold text-white uppercase tracking-tight">Request Submitted</h2>
              <p className="text-[#8FAEDB] text-sm max-w-sm mx-auto">
                Your allocation request for <span className="text-white font-semibold">{deal.title}</span> is now under review by the Investment Committee.
              </p>
              <div className="pt-4">
                <Button onClick={onClose} variant="outline" className="w-full">Back to Dashboard</Button>
              </div>
            </div>
          )}
        </div>
      </Card>
    </div>
  );
};

